{{#if: {{hasTemplate|{{{2|{{FULLPAGENAME}}}}}|User:MiszaBot/config}}
  | {{#switch: {{{1|}}}
      |bot = Lowercase sigmabot III
      |age = {{#if: {{tmpv|{{{2|{{FULLPAGENAME}}}}}|User:MiszaBot/config|1|algo}}
               | {{#invoke:String|match| {{tmpv|{{{2|{{FULLPAGENAME}}}}}|User:MiszaBot/config|1|algo}} |^%s*old%s*%((%d+)[dh]?%)%s*$|nomatch=}}
