                     | h = hours
                     | #DEFAULT = seconds
                   }}
               }}
      |minkeepthreads |minthreadsleft |min  = {{tmpv|{{{2|{{FULLPAGENAME}}}}}|User:MiszaBot/config|1|minthreadsleft}}
	  |minarchthreads |minthreadstoarchive  = {{tmpv|{{{2|{{FULLPAGENAME}}}}}|User:MiszaBot/config|1|minthreadstoarchive}}
      |#DEFAULT = 
    }}<noinclude><!-- end #switch MiszaBot--></noinclude>
  | <!--else not MiszaBot-->
